`Approach 2: Optimized 1D DP using Parity of Moves`#include &lt;iostream&gt;
#include &lt;vector&gt;
#include &lt;algorithm&gt;
using namespace std;

int main(){
    int N, K;
    cin &gt;&gt; N &gt;&gt; K;
    vector&lt;int&gt; price(N);
    for (int i = 0; i &lt; N; i++){
        cin &gt;&gt; price[i];
    }

    int negInf = -1000000000;
    // dp[j]: maximum profit after j market visits.
    // Even j means not holding (sell state), odd j means holding (buy state).
    vector&lt;int&gt; dp(K+1, negInf);
    dp[0] = 0;

    for (int p : price) {
        for (int j = K; j &gt;= 1; j--){
            if(j % 2 == 1){  // Buy state: update by buying today.
                dp[j] = max(dp[j], dp[j-1] - p);
            } else {         // Sell state: update by selling today.
                dp[j] = max(dp[j], dp[j-1] + p);
            }
        }
    }

    int ans = 0;
    // Only consider even j (not holding any buffalo) for the final answer.
    for (int j = 0; j &lt;= K; j += 2){
        ans = max(ans, dp[j]);
    }
    cout &lt;&lt; ans &lt;&lt; "\n";
    return 0;
}
